select distinct se.administrative_office from swm_employee se where 1 = 1 and se.administrative_office is not null and se.administrative_office <> ''
and se.department = #{department,jdbcType=VARCHAR}
union select '' order by 1

select distinct se.team from swm_employee se where 1 = 1 and se.team is not null and se.team <> ''
and se.administrative_office = #{office,jdbcType=VARCHAR}
